@app.route("/oauth/authorize")
def oauth_authorize():
    tenant_id = request.args.get("tenant")
    if not tenant_id:
        abort(400, description="Missing tenant")

    cfg = get_tenant_config(tenant_id)
    domain = cfg["domain"]
    client_id = cfg["client_id"]
    authorization_endpoint = cfg["authorization_endpoint"]

